-- Create "ops_error_logs" table
CREATE TABLE "ops_error_logs" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "occurred_at" timestamptz NOT NULL,
  "request_id" character varying NOT NULL DEFAULT '',
  "trace_id" character varying NOT NULL DEFAULT '',
  "user_id" bigint NULL,
  "api_key_id" bigint NULL,
  "account_id" bigint NULL,
  "provider_id" bigint NULL,
  "platform" character varying NOT NULL DEFAULT '',
  "source_endpoint" character varying NOT NULL DEFAULT '',
  "target_protocol" character varying NOT NULL DEFAULT '',
  "model" character varying NOT NULL DEFAULT '',
  "status_code" bigint NULL,
  "upstream_request_id" character varying NOT NULL DEFAULT '',
  "attempt_no" bigint NOT NULL DEFAULT 1,
  "latency_ms" bigint NOT NULL DEFAULT 0,
  "input_tokens" bigint NOT NULL DEFAULT 0,
  "output_tokens" bigint NOT NULL DEFAULT 0,
  "usage_estimated" boolean NOT NULL DEFAULT false,
  "error_class" character varying NOT NULL DEFAULT 'unknown',
  "error_phase" character varying NOT NULL DEFAULT 'upstream',
  "error_owner" character varying NOT NULL DEFAULT 'provider',
  "error_source" character varying NOT NULL DEFAULT 'upstream_http',
  "error_message" text NOT NULL DEFAULT '',
  "error_body_excerpt" text NOT NULL DEFAULT '',
  "upstream_errors_json" jsonb NULL,
  "resolution" character varying NOT NULL DEFAULT 'open',
  "resolution_note" text NOT NULL DEFAULT '',
  "resolved_at" timestamptz NULL,
  "resolved_by_id" bigint NULL,
  PRIMARY KEY ("id")
);
-- Create index "opserrorlog_account_id_occurred_at" to table: "ops_error_logs"
CREATE INDEX "opserrorlog_account_id_occurred_at" ON "ops_error_logs" ("account_id", "occurred_at");
-- Create index "opserrorlog_api_key_id_occurred_at" to table: "ops_error_logs"
CREATE INDEX "opserrorlog_api_key_id_occurred_at" ON "ops_error_logs" ("api_key_id", "occurred_at");
-- Create index "opserrorlog_error_class_occurred_at" to table: "ops_error_logs"
CREATE INDEX "opserrorlog_error_class_occurred_at" ON "ops_error_logs" ("error_class", "occurred_at");
-- Create index "opserrorlog_occurred_at" to table: "ops_error_logs"
CREATE INDEX "opserrorlog_occurred_at" ON "ops_error_logs" ("occurred_at");
-- Create index "opserrorlog_platform_occurred_at" to table: "ops_error_logs"
CREATE INDEX "opserrorlog_platform_occurred_at" ON "ops_error_logs" ("platform", "occurred_at");
-- Create index "opserrorlog_provider_id_occurred_at" to table: "ops_error_logs"
CREATE INDEX "opserrorlog_provider_id_occurred_at" ON "ops_error_logs" ("provider_id", "occurred_at");
-- Create index "opserrorlog_request_id" to table: "ops_error_logs"
CREATE INDEX "opserrorlog_request_id" ON "ops_error_logs" ("request_id");
-- Create index "opserrorlog_resolution_occurred_at" to table: "ops_error_logs"
CREATE INDEX "opserrorlog_resolution_occurred_at" ON "ops_error_logs" ("resolution", "occurred_at");
-- Create index "opserrorlog_status_code_occurred_at" to table: "ops_error_logs"
CREATE INDEX "opserrorlog_status_code_occurred_at" ON "ops_error_logs" ("status_code", "occurred_at");
-- Create index "opserrorlog_target_protocol_occurred_at" to table: "ops_error_logs"
CREATE INDEX "opserrorlog_target_protocol_occurred_at" ON "ops_error_logs" ("target_protocol", "occurred_at");
-- Create index "opserrorlog_trace_id" to table: "ops_error_logs"
CREATE INDEX "opserrorlog_trace_id" ON "ops_error_logs" ("trace_id");
-- Create index "opserrorlog_upstream_request_id" to table: "ops_error_logs"
CREATE INDEX "opserrorlog_upstream_request_id" ON "ops_error_logs" ("upstream_request_id");
-- Create index "opserrorlog_user_id_occurred_at" to table: "ops_error_logs"
CREATE INDEX "opserrorlog_user_id_occurred_at" ON "ops_error_logs" ("user_id", "occurred_at");
